func solve(prices []int64, strategy []int64, k int64) int64 {
	n := len(prices)
	if n == 0 {
		return 0
	}
	prefixOriginal := make([]int64, n+1)
	prefixPrices := make([]int64, n+1)
	for i := 0; i < n; i++ {
		prefixOriginal[i+1] = prefixOriginal[i] + strategy[i]*prices[i]
		prefixPrices[i+1] = prefixPrices[i] + prices[i]
	}
	originalProfit := prefixOriginal[n]
	maxDelta := -1000000000000000000
	for i := 0; i <= n-int(k); i++ {
		originalSum := prefixOriginal[i+int(k)] - prefixOriginal[i]
		half := int(k) / 2
		sumSecond := prefixPrices[i+int(k)] - prefixPrices[i+half]
		delta := sumSecond - originalSum
		if delta > maxDelta {
			maxDelta = delta
		}
	}
	var maxProfit int64
